      { "name": "Channel Adapters (Email, SMS)", "responsibility": "Translate a canonical NotificationPayload into provider-specific API calls (SendGrid, Twilio, etc.).", "boundaries": "Each adapter implements a common interface. Provider SDK details do not leak beyond the adapter." },
      { "name": "Dead Letter Queue (DLQ)", "responsibility": "Captures notifications that exhaust all retry attempts. Enables manual inspection and replay.", "boundaries": "Same queue technology as the main queue. Monitored with alerts — not silently ignored." },
      { "name": "Notification Log (Database Table)", "responsibility": "Records every notification attempt, status, and channel for auditability and idempotency checks.", "boundaries": "Simple append-mostly table. Not a separate service — a table in the existing database." }
    ],
    "interfaces": [
      { "from": "Delivery Service", "to": "Event Queue", "contract": "Publishes DeliveryStatusChanged event: { eventId, deliveryId, status, customerId, timestamp }", "coupling_type": "loose — fire-and-forget publish; delivery service does not wait for notification outcome" },
      { "from": "Event Queue", "to": "Notification Worker", "contract": "Worker polls/receives events. Acknowledges after successful dispatch or routes to DLQ after max retries.", "coupling_type": "loose — queue mediates; worker and publisher are temporally decoupled" },
      { "from": "Notification Worker", "to": "Channel Adapters", "contract": "Worker calls adapter.send(notificationPayload): Promise<Result<Success, ChannelError>>. Adapter returns success or typed failure.", "coupling_type": "loose — plugin interface; worker depends on abstraction, not concrete providers" },
