    ],
    "context_map": [
      { "upstream": "Delivery", "downstream": "Notification", "relationship": "Customer-Supplier via domain events. Delivery context publishes events; Notification context consumes them. Notification never calls back into Delivery. Delivery team owns the event schema." }
    ]
