      "src/notification/adapters/ChannelAdapter.ts — interface definition: send(payload): Promise<Result>",
      "src/notification/adapters/EmailAdapter.ts — SendGrid/SES implementation",
      "src/notification/adapters/SmsAdapter.ts — Twilio implementation",
      "src/notification/persistence/NotificationLog.ts — entity, migration, idempotency queries",
