    ],
    "assumptions": [
      "Notification volume is proportional to deliveries — likely thousands to low tens-of-thousands per day, not millions",
      "The team has access to a managed cloud platform (AWS, GCP, or at minimum a Redis instance)",
      "Email and SMS providers offer standard REST APIs with reasonable reliability (SendGrid, Twilio, etc.)",
      "The delivery service already has a relational database where the outbox table can live"
    ]
  }
